namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the notification center!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New feature: dark mode is now available."),
        });
    }

    /// <summary>Returns all notifications available at the time of the call.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > sinceId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called by a hosted service so every connected page sees new data.
    /// </summary>
    internal void AddRandom()
    {
        string[] samples =
        [
            "Deployment completed for service-api.",
            "Disk usage above 80% on db-server-03.",
            "User 'jdoe' logged in from a new device.",
            "Scheduled backup finished successfully.",
            "Pull request #42 was merged.",
            "Certificate for *.example.com expires in 7 days.",
        ];

        lock (_lock)
        {
            var msg = samples[Random.Shared.Next(samples.Length)];
            _notifications.Add(CreateNotification(msg));
        }
    }

    private Notification CreateNotification(string message)
    {
        return new Notification(_nextId++, message, DateTime.UtcNow);
    }
}

namespace BlazorNotifications.Services;

/// <summary>
/// Background hosted service that periodically adds fake notifications
/// so the polling page has something new to pick up.
/// </summary>
public class NotificationGeneratorService(NotificationService notifications) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            notifications.AddRandom();
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationService NotificationSvc

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in _notifications.OrderByDescending(x => x.Id))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted ms-3 text-nowrap">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    // Runs during SSR *and* again when the component becomes interactive.
    // PersistentComponentState would also work here, but tracking the
    // high-water-mark Id is simpler for a polling scenario.
    protected override void OnInitialized()
    {
        _notifications = NotificationSvc.GetAll();
    }

    // Called only once, and only when the component is interactive
    // (never during static SSR), making it the right place to start polling.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            var latestId = _notifications.Count > 0
                ? _notifications.Max(n => n.Id)
                : 0;

            var newer = NotificationSvc.GetSince(latestId);

            if (newer.Count > 0)
            {
                await InvokeAsync(() =>
                {
                    _notifications.AddRange(newer);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

